import os
import shutil
from datetime import date
import tarfile
import zipfile
import py7zr

def create_archive(directory, format):
    today = date.today()
    backup_dir = "/backups"  # replace with your actual path to the backups directory
    
    if not os.path.exists(backup_dir):
        os.makedirs(backup_dir)
        
    archive_name = f'{directory.split("/")[-1]}_{today}.{format}'
    
    if format == 'tar.gz':
        with tarfile.open(os.path.join(backup_dir, archive_name), "w:gz") as tar:
            tar.add(directory, arcname=os.path.basename(directory))
            
    elif format == 'tar.bz2':
        with tarfile.open(os.path.join(backup_dir, archive_name), "w:bz2") as tar:
            tar.add(directory, arcname=os.path.basename(directory))
            
    elif format == 'zip':
        with zipfile.ZipFile(os.path.join(backup_dir, archive_name), 'w', zipfile.ZIP_DEFLATED) as zf:
            zf.write(directory, arcname=os.path.basename(directory))
            
    elif format == '7z':
        with py7zr.SevenZipFile(os.path.join(backup_dir, archive_name), 'w') as zf:
            zf.writeall(directory, arcname=os.path.basename(directory))
            
    else:
        print("Unsupported format")
        
# usage example
